"import { useState, useEffect } from 'react';
import { Sliders, Eye, EyeOff, Check, Clipboard, HelpCircle, RefreshCw } from 'lucide-react';

interface FBPageAccount {
  id: string;
  name: string;
  access_token: string;
  category?: string;
  followers_count?: number;
}

export default function SettingsPortal() {
  // OpenRouter key state
  const [openRouterKey, setOpenRouterKey] = useState(() => localStorage.getItem('openrouter_key') || '');
  const [showOrKey, setShowOrKey] = useState(false);
  const [orSaved, setOrSaved] = useState(false);

  // Facebook tokens states
  const [fbUserToken, setFbUserToken] = useState(() => localStorage.getItem('fb_user_token') || '');
  const [showFbToken, setShowFbToken] = useState(false);
  const [fbUserSaved, setFbUserSaved] = useState(false);

  // Extracted pages state
  const [fbPages, setFbPages] = useState<FBPageAccount[]>([]);
  const [loadingPages, setLoadingPages] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);

  // Saved page tokens local registry (pageId -> pageAccessToken map)
  const [savedPageTokens, setSavedPageTokens] = useState<Record<string, string>>(() => {
    try {
      return JSON.parse(localStorage.getItem('fb_page_tokens_map') || '{}');
    } catch {
      return {};
    }
  });

  // State to track copied tokens for dynamic UI feedback
  const [copiedId, setCopiedId] = useState<string | null>(null);

  // Automatically fade out "Saved!" feedback
  useEffect(() => {
    if (orSaved) {
      const t = setTimeout(() => setOrSaved(false), 2000);
      return () => clearTimeout(t);
    }
  }, [orSaved]);

